import{_ as e,o as a,c as o,a3 as d}from"./chunks/framework.CRbjHCyB.js";const k=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"zh/clice/guide/configuration.md","filePath":"zh/clice/guide/configuration.md"}'),i={name:"zh/clice/guide/configuration.md"};function r(s,t,c,l,h,n){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>clice 从工作区根目录的 <code>clice.toml</code> 中读取配置。配置也可以通过 LSP <code>initializationOptions</code>（JSON 格式）传入。</p><h2 id="变量替换" tabindex="-1">变量替换 <a class="header-anchor" href="#变量替换" aria-label="Permalink to &quot;变量替换&quot;">​</a></h2><p>字符串值中支持以下变量：</p><table tabindex="0"><thead><tr><th>变量</th><th>说明</th></tr></thead><tbody><tr><td><code>${workspace}</code></td><td>客户端提供的工作区目录</td></tr></tbody></table><h2 id="project" tabindex="-1">Project <a class="header-anchor" href="#project" aria-label="Permalink to &quot;Project&quot;">​</a></h2><h3 id="project-clang-tidy" tabindex="-1"><code>project.clang_tidy</code> <a class="header-anchor" href="#project-clang-tidy" aria-label="Permalink to &quot;`project.clang_tidy`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>bool</code></td><td><code>false</code></td></tr></tbody></table><p>启用实验性的 clang-tidy 诊断。</p><h3 id="project-max-active-file" tabindex="-1"><code>project.max_active_file</code> <a class="header-anchor" href="#project-max-active-file" aria-label="Permalink to &quot;`project.max_active_file`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>int</code></td><td><code>8</code></td></tr></tbody></table><p>内存中保持的最大活跃文件数。超过限制时，最近最少使用的文件会被淘汰。</p><h3 id="project-cache-dir" tabindex="-1"><code>project.cache_dir</code> <a class="header-anchor" href="#project-cache-dir" aria-label="Permalink to &quot;`project.cache_dir`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>string</code></td><td><code>$XDG_CACHE_HOME/clice/&lt;hash&gt;</code> 或 <code>${workspace}/.clice</code></td></tr></tbody></table><p>PCH 和 PCM 缓存文件的存储目录。默认使用 XDG_CACHE_HOME（或 <code>~/.cache</code>）下的工作区专用哈希子目录。如果 XDG 目录无法创建，则回退到 <code>${workspace}/.clice</code>。</p><h3 id="project-index-dir" tabindex="-1"><code>project.index_dir</code> <a class="header-anchor" href="#project-index-dir" aria-label="Permalink to &quot;`project.index_dir`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>string</code></td><td><code>${cache_dir}/index</code></td></tr></tbody></table><p>索引文件的存储目录。</p><h3 id="project-logging-dir" tabindex="-1"><code>project.logging_dir</code> <a class="header-anchor" href="#project-logging-dir" aria-label="Permalink to &quot;`project.logging_dir`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>string</code></td><td><code>${cache_dir}/logs</code></td></tr></tbody></table><p>日志文件目录。</p><h3 id="project-compile-commands-paths" tabindex="-1"><code>project.compile_commands_paths</code> <a class="header-anchor" href="#project-compile-commands-paths" aria-label="Permalink to &quot;`project.compile_commands_paths`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>array of string</code></td><td><code>[]</code></td></tr></tbody></table><p>搜索 <code>compile_commands.json</code> 文件的路径。可以是直接的文件路径，也可以是目录（会在其中查找 <code>compile_commands.json</code>）。为空（默认）时，clice 会先搜索工作区根目录，再依次搜索其各个直接子目录，使用找到的第一个 <code>compile_commands.json</code>。</p><h3 id="project-enable-indexing" tabindex="-1"><code>project.enable_indexing</code> <a class="header-anchor" href="#project-enable-indexing" aria-label="Permalink to &quot;`project.enable_indexing`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>bool</code></td><td><code>true</code></td></tr></tbody></table><p>启用后台索引，用于跨 TU 功能（查找引用、工作区符号等）。</p><h3 id="project-idle-timeout-ms" tabindex="-1"><code>project.idle_timeout_ms</code> <a class="header-anchor" href="#project-idle-timeout-ms" aria-label="Permalink to &quot;`project.idle_timeout_ms`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>int</code></td><td><code>3000</code></td></tr></tbody></table><p>最后一次编辑后开始后台索引的空闲等待时间（毫秒）。</p><h3 id="project-stateful-worker-count" tabindex="-1"><code>project.stateful_worker_count</code> <a class="header-anchor" href="#project-stateful-worker-count" aria-label="Permalink to &quot;`project.stateful_worker_count`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>uint32</code></td><td><code>2</code></td></tr></tbody></table><p>有状态工作进程数量。这些进程在内存中持有 AST，服务查询（hover、semantic tokens 等）。</p><h3 id="project-stateless-worker-count" tabindex="-1"><code>project.stateless_worker_count</code> <a class="header-anchor" href="#project-stateless-worker-count" aria-label="Permalink to &quot;`project.stateless_worker_count`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>uint32</code></td><td><code>max(cores/2, 2)</code></td></tr></tbody></table><p>无状态工作进程数量。处理临时任务（PCH/PCM 构建、补全、签名帮助）。</p><h3 id="project-worker-memory-limit" tabindex="-1"><code>project.worker_memory_limit</code> <a class="header-anchor" href="#project-worker-memory-limit" aria-label="Permalink to &quot;`project.worker_memory_limit`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>uint64</code></td><td><code>4294967296</code>（4 GB）</td></tr></tbody></table><p>每个工作进程的内存限制（字节）。超过限制的工作进程会被重启。</p><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><p><code>[[rules]]</code> 是规则对象数组。规则按声明顺序匹配——后面的规则覆盖前面的。</p><h3 id="rules-patterns" tabindex="-1"><code>[rules].patterns</code> <a class="header-anchor" href="#rules-patterns" aria-label="Permalink to &quot;`[rules].patterns`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>array of string</code></td><td><code>[]</code></td></tr></tbody></table><p>匹配文件路径的 glob 模式：</p><ul><li><code>*</code> — 匹配路径段中的一个或多个字符</li><li><code>?</code> — 匹配路径段中的单个字符</li><li><code>**</code> — 匹配任意数量的路径段，包括零个</li><li><code>{}</code> — 分组条件（如 <code>**/*.{h,cpp}</code>）</li><li><code>[]</code> — 字符范围（如 <code>example.[0-9]</code>）</li><li><code>[!...]</code> — 排除字符范围</li></ul><h3 id="rules-append" tabindex="-1"><code>[rules].append</code> <a class="header-anchor" href="#rules-append" aria-label="Permalink to &quot;`[rules].append`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>array of string</code></td><td><code>[]</code></td></tr></tbody></table><p>追加到编译命令的标志。例如：<code>[&quot;-std=c++20&quot;, &quot;-DNDEBUG&quot;]</code>。</p><h3 id="rules-remove" tabindex="-1"><code>[rules].remove</code> <a class="header-anchor" href="#rules-remove" aria-label="Permalink to &quot;`[rules].remove`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td><code>array of string</code></td><td><code>[]</code></td></tr></tbody></table><p>从编译命令中移除的标志。例如：<code>[&quot;-Wall&quot;, &quot;-Werror&quot;]</code>。</p><h2 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h2><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">project</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">max_active_file = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">compile_commands_paths = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;${workspace}/build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;${workspace}/cmake-build-debug&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">clang_tidy = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">patterns = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;**/*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">append = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-std=c++23&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">patterns = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;**/test/**&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">append = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-DTEST_MODE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div>',53)])])}const b=e(i,[["render",r]]);export{k as __pageData,b as default};
